import { Handle, Position } from "@xyflow/react";
import React from "react";
import { StatusBadge } from "../../workflow";

interface BaseNodeProps {
	data: {
		label: string;
		status?: "draft" | "active" | "error" | "success";
		description?: string;
	};
	selected?: boolean;
}

function BaseNode({ title, data, selected, children, isSource, isTarget }: BaseNodeProps & { title: string, children?: React.ReactNode, isSource?: boolean, isTarget?: boolean }) {
	return (
		<div
			className={`
				min-w-[200px] rounded-[var(--workflow-panel-radius)] border bg-[var(--workflow-panel-background)] px-4 py-3 shadow-sm transition-colors
				${selected ? "border-[color:var(--vscode-focusBorder)] ring-1 ring-[color:var(--vscode-focusBorder)]" : "border-[color:var(--workflow-panel-border-color)]"}
			`}
		>
			{isTarget && <Handle type="target" position={Position.Top} className="!bg-[color:var(--vscode-focusBorder)]" />}

			<div className="flex items-start justify-between gap-3">
				<div>
					<p className="text-[color:var(--vscode-descriptionForeground)] text-xs uppercase tracking-wider font-semibold">
						{title}
					</p>
					<p className="mt-1 text-[color:var(--vscode-foreground)] font-medium text-sm">
						{data.label}
					</p>
					{data.description && (
						<p className="mt-1 max-w-[200px] text-[color:var(--vscode-descriptionForeground)] text-xs truncate">
							{data.description}
						</p>
					)}
				</div>
				{data.status && (
					<StatusBadge status={data.status} />
				)}
			</div>

			{children && <div className="mt-3">{children}</div>}

			{isSource && <Handle type="source" position={Position.Bottom} className="!bg-[color:var(--vscode-focusBorder)]" />}
		</div>
	);
}

export function ActionNode(props: BaseNodeProps) {
	return <BaseNode title="Action" {...props} isSource isTarget />;
}

export function SourceNode(props: BaseNodeProps) {
	return <BaseNode title="Source" {...props} isSource />;
}

export function ConditionNode(props: BaseNodeProps) {
	return <BaseNode title="Condition" {...props} isSource isTarget />;
}

export function ScheduleNode(props: BaseNodeProps) {
	return <BaseNode title="Schedule" {...props} isSource />;
}

import type { NodeTypes } from "@xyflow/react";
import { ActionNode, ConditionNode, ScheduleNode, SourceNode } from "./base-nodes";

export const workflowNodeTypes: NodeTypes = {
	action: ActionNode,
	source: SourceNode,
	condition: ConditionNode,
	schedule: ScheduleNode,
};

import {
	Background,
	Controls,
	ReactFlow,
	type Edge,
	type Node,
	type OnConnect,
	type OnEdgesChange,
	type OnNodesChange,
} from "@xyflow/react";
import "@xyflow/react/dist/style.css";
import React from "react";
import { workflowNodeTypes } from "./nodes";

interface WorkflowGraphProps {
	nodes: Node[];
	edges: Edge[];
	onNodesChange?: OnNodesChange;
	onEdgesChange?: OnEdgesChange;
	onConnect?: OnConnect;
	onNodeClick?: (event: React.MouseEvent, node: Node) => void;
	readonly?: boolean;
}

export function WorkflowGraph({
	nodes,
	edges,
	onNodesChange,
	onEdgesChange,
	onConnect,
	onNodeClick,
	readonly = false,
}: WorkflowGraphProps) {
	return (
		<div className="h-full w-full rounded-[var(--workflow-panel-radius)] border border-[color:var(--workflow-panel-border-color)] overflow-hidden bg-[color:var(--workflow-panel-muted-background)]">
			<ReactFlow
				nodes={nodes}
				edges={edges}
				onNodesChange={onNodesChange}
				onEdgesChange={onEdgesChange}
				onConnect={onConnect}
				onNodeClick={onNodeClick}
				nodeTypes={workflowNodeTypes}
				fitView
				elementsSelectable={!readonly}
				nodesConnectable={!readonly}
				nodesDraggable={!readonly}
			>
				<Background color="var(--vscode-descriptionForeground)" gap={16} size={1} />
				<Controls className="!bg-[color:var(--vscode-editor-background)] !border-[color:var(--workflow-panel-border-color)] fill-[color:var(--vscode-foreground)]" />
			</ReactFlow>
		</div>
	);
}

